module RefModule (
    input [3:0] num,
    output [3:0] twos_comp
);

wire [3:0] complement;
  wire _n01 = ~num[0] ^ 1[0];
  wire _c01 = ~num[0] & 1[0];
  wire _n02 = ~num[1] ^ 1[1] ^ _c01;
  wire _c02 = (~num[1] & 1[1]) | (~num[1] & _c01) | (1[1] & _c01);
  wire _n03 = ~num[2] ^ 1[2] ^ _c02;
  wire _c03 = (~num[2] & 1[2]) | (~num[2] & _c02) | (1[2] & _c02);
  wire _n04 = ~num[3] ^ 1[3] ^ _c03;
  wire _c04 = (~num[3] & 1[3]) | (~num[3] & _c03) | (1[3] & _c03);
  assign complement = {_n01, _n02, _n03, _n04};

assign twos_comp = complement;

endmodule
